import{_ as a,o as d,c as e,a2 as r}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"综合账户","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/account-types/comprehensive-account.md","filePath":"zh-CN/account/account-types/comprehensive-account.md"}'),o={name:"account/account-types/comprehensive-account.md"};function n(c,t,i,h,l,s){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="综合账户" tabindex="-1">综合账户 <a class="header-anchor" href="#综合账户" aria-label="Permalink to &quot;综合账户&quot;">​</a></h1><p>长桥综合账户是进行证券交易的主账户，分为香港综合账户和新加坡综合账户，分别受香港证监会（SFC）和新加坡金融管理局（MAS）监管。一个客户可同时持有两个账户，资金相互独立。</p><h2 id="账户对比" tabindex="-1">账户对比 <a class="header-anchor" href="#账户对比" aria-label="Permalink to &quot;账户对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>香港综合账户</th><th>新加坡综合账户</th></tr></thead><tbody><tr><td>账户编号前缀</td><td>H（如 H12345678）</td><td>SG（如 SG12345678）</td></tr><tr><td>监管机构</td><td>香港证监会（SFC）</td><td>新加坡金融管理局（MAS）</td></tr><tr><td>港股交易</td><td>✓</td><td>✓</td></tr><tr><td>港股打新（IPO）</td><td>✓</td><td>—</td></tr><tr><td>美股交易</td><td>✓</td><td>✓</td></tr><tr><td>新加坡股票</td><td>—</td><td>✓</td></tr><tr><td>美股期权</td><td>✓</td><td>✓</td></tr><tr><td>融资融券</td><td>✓</td><td>✓</td></tr><tr><td>港元账户</td><td>✓</td><td>—</td></tr><tr><td>美元账户</td><td>✓</td><td>✓</td></tr><tr><td>新加坡元账户</td><td>—</td><td>✓</td></tr><tr><td>余额通</td><td>香港余额通</td><td>新加坡余额通</td></tr></tbody></table><h2 id="入金方式" tabindex="-1">入金方式 <a class="header-anchor" href="#入金方式" aria-label="Permalink to &quot;入金方式&quot;">​</a></h2><p><strong>香港综合账户</strong>：FPS 转数快、eDDA、网银转账、银证转账、ATM 与柜台、电汇</p><p><strong>新加坡综合账户</strong>：PayNow、DDA、网银与电汇、Wise</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/wiki/account/opening/open-account">如何开通综合账户</a> — 开户资格、认证流程、注销</li><li><a href="/wiki/account/account-types/intraday-margin">日内融账户</a> — 支持当日回转交易的特殊账户类型</li><li><a href="/wiki/account/account-types/paper-trading">模拟账户</a> — 用虚拟资金练习交易</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/account">开户与账户</a></li></ul>',11)])])}const _=a(o,[["render",n]]);export{p as __pageData,_ as default};
